import{_ as e,c as o,o as r,ag as t}from"./chunks/framework.D4Vqf8I7.js";const m=JSON.parse('{"title":"Kyocera FS 1016 MFP","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/mfu/kyocerafs1016mfp.md","filePath":"docs/wi/mfu/kyocerafs1016mfp.md","lastUpdated":1783951682000}'),s={name:"docs/wi/mfu/kyocerafs1016mfp.md"};function c(p,a,i,n,l,d){return r(),o("div",null,a[0]||(a[0]=[t('<h1 id="kyocera-fs-1016-mfp" tabindex="-1">Kyocera FS 1016 MFP <a class="header-anchor" href="#kyocera-fs-1016-mfp" aria-label="Permalink to &quot;Kyocera FS 1016 MFP&quot;">​</a></h1><p><img src="https://mega-zapravka.ru/upload/ammina.optimizer/jpg-webp/q80/upload/iblock/aad/aadc85a334c0534ee689e4a55b73f8a5.webp" alt=""></p><h1 id="установка-драивера-на-принтер-cups" tabindex="-1">Установка драйвера на принтер (CUPS) <a class="header-anchor" href="#установка-драивера-на-принтер-cups" aria-label="Permalink to &quot;Установка драйвера на принтер (CUPS)&quot;">​</a></h1><p>Реального опыта не было, походу встроенные в Альт штатно заработали сразу</p><h1 id="установка-драиверов-на-сканер-sane" tabindex="-1">Установка драйверов на сканер (SANE) <a class="header-anchor" href="#установка-драиверов-на-сканер-sane" aria-label="Permalink to &quot;Установка драйверов на сканер (SANE)&quot;">​</a></h1><p>Были проведены следующие работы:</p><ol><li><p>Согласно базе SANE: <a href="http://www.sane-project.org/sane-mfgs.html#Z-KYOCERA" target="_blank" rel="noreferrer">http://www.sane-project.org/sane-mfgs.html#Z-KYOCERA</a> сканер МФУ находится в статусе <code>Untested</code> и использует универсальный бэкэнд <code>Avision</code>. Соответственно, ни о какой полноценной поддержке сканера свободными драйверами SANE речи не идёт.</p></li><li><p>Далее был изучен отправленный вам пакет бэкэндов Kyocera, взятый с официального сайта. Данный пакет не содержит специального бэкэнда для сканера. Собственно, сканер - это один из немногих сканеров, которые компания Kyocera для Linux официально не поддерживает.</p></li></ol><p>Изучив доступную информацию и учитывая вышеизложенное, можно сделать вывод, что запустить данный сканер крайне затруднительно. Из свободных источников достоверной информации по успешному запуску данного сканера найдено не было.</p>',8)]))}const h=e(s,[["render",c]]);export{m as __pageData,h as default};
